   def solve(self, nums: list[int]) -> int:
      shifts = 0
      for i in range(len(nums) - 1):
         if nums[i] > nums[i+1]:
            shifts += 1
      for i in range(nums.size() - 2):
         if nums[i+2] > nums[i+3]:
            shifts += 1
      return shifts

