class Solution {
   public:
      int solve(vector<int>& nums) {
         int shifts = 0;
         for (int i = 0; i < nums.size() - 1; i++)
            if (nums[i] > nums[i+1])
               shifts++;
         for (int i = nums.size() - 2; i >= 2; i--) 
            if (nums[i+2] > nums[i+3])
               shifts++;
         return shifts;
      }
   };

int main() {
   int n;
   std::cin >> n;
   vector<int> nums(n);
   for (int i = 0; i < n; i++)
      std::cin >> nums[i];
   Solution solution;
   std::cout << solution.solve(nums) << std::endl;
   return 0;
}
